// ============================================================
// SEED COMPLETO — KaledAcademy AI SaaS Engineering Bootcamp
// 4 Módulos · 16 Semanas · 48 Sesiones · 144 Horas
// Ejecutar: npx ts-node prisma/seed-kaledacademy.ts
//           (o incluir en prisma/seed.ts principal)
// ============================================================

import { PrismaClient, BadgeCondition, SessionType, DayOfWeek, CRALPhase, Prisma } from "@prisma/client";
import bcrypt from "bcryptjs";

const prisma = new PrismaClient();

async function main() {
  console.log("🚀 Iniciando seed de KaledAcademy...\n");

  // ── 1. TENANT ────────────────────────────────────────────
  console.log("📦 Creando tenant KaledAcademy...");
  const tenant = await prisma.tenant.upsert({
    where: { slug: "kaledacademy" },
    create: {
      name: "KaledAcademy",
      slug: "kaledacademy",
      domain: "academy.kaledsoft.tech",
      email: "academia@kaledsoft.tech",
      plan: "PRO",
      status: "ACTIVO",
      branding: {
        create: {
          primaryColor: "#161A22",
          secondaryColor: "#3B82F6",
          accentColor: "#10B981",
          fontFamily: "Inter",
          darkMode: true,
          footerText: "KaledSoft Technologies · Colombia · kaledsoft.tech",
        },
      },
    },
    update: { status: "ACTIVO" },
  });
  console.log(`   ✓ Tenant: ${tenant.name} (${tenant.slug})\n`);

  // ── 2. ROLES ─────────────────────────────────────────────
  console.log("👥 Creando roles de la academia...");
  const roleAdmin = await prisma.role.upsert({
    where: { name_tenantId: { name: "ACADEMY_ADMIN", tenantId: tenant.id } },
    create: { name: "ACADEMY_ADMIN", description: "Administrador de la academia", permissions: ["*"], tenantId: tenant.id },
    update: {},
  });
  const roleTeacher = await prisma.role.upsert({
    where: { name_tenantId: { name: "ACADEMY_TEACHER", tenantId: tenant.id } },
    create: { name: "ACADEMY_TEACHER", description: "Instructor del bootcamp", permissions: ["courses:read","lessons:write","deliverables:review","cohorts:read"], tenantId: tenant.id },
    update: {},
  });
  const roleStudent = await prisma.role.upsert({
    where: { name_tenantId: { name: "ACADEMY_STUDENT", tenantId: tenant.id } },
    create: { name: "ACADEMY_STUDENT", description: "Estudiante del bootcamp", permissions: ["courses:read","lessons:read","quizzes:write","deliverables:submit"], tenantId: tenant.id },
    update: {},
  });
  console.log("   ✓ Roles: ACADEMY_ADMIN, ACADEMY_TEACHER, ACADEMY_STUDENT\n");

  // ── 3. USUARIOS DEMO ──────────────────────────────────────
  console.log("👤 Creando usuarios demo...");
  const pwHash = await bcrypt.hash("KaledSoft2025!", 10);

  const userAdmin = await prisma.user.upsert({
    where: { email: "luisg@kaledsoft.tech" },
    create: {
      email: "luisg@kaledsoft.tech",
      name: "Luis Guillermo Salinas",
      password: pwHash,
      isActive: true,
      platformRole: "ACADEMY_ADMIN",
      tenantId: tenant.id,
      roleId: roleAdmin.id,
    },
    update: {},
  });

  const _userInstructor = await prisma.user.upsert({
    where: { email: "instructor@kaledsoft.tech" },
    create: {
      email: "instructor@kaledsoft.tech",
      name: "Kaled Instructor",
      password: pwHash,
      isActive: true,
      platformRole: "ACADEMY_TEACHER",
      tenantId: tenant.id,
      roleId: roleTeacher.id,
    },
    update: {},
  });

  const studentEmails = [
    { email: "andres@demo.kaledsoft.tech", name: "Andrés Martínez" },
    { email: "valentina@demo.kaledsoft.tech", name: "Valentina Ríos" },
    { email: "carlos@demo.kaledsoft.tech", name: "Carlos Herrera" },
    { email: "juliana@demo.kaledsoft.tech", name: "Juliana Pérez" },
  ];
  const students = await Promise.all(
    studentEmails.map(s =>
      prisma.user.upsert({
        where: { email: s.email },
        create: { email: s.email, name: s.name, password: pwHash, isActive: true, platformRole: "ACADEMY_STUDENT", tenantId: tenant.id, roleId: roleStudent.id },
        update: {},
      })
    )
  );
  console.log(`   ✓ Admin, instructor y ${students.length} estudiantes demo\n`);

  // ── 4. CURSO PRINCIPAL ────────────────────────────────────
  console.log("📚 Creando el bootcamp AI SaaS Engineering...");
  const course = await prisma.academyCourse.upsert({
    where: { id: "kaledacademy-bootcamp-2025" },
    create: {
      id: "kaledacademy-bootcamp-2025",
      title: "AI SaaS Engineering Bootcamp",
      description: "Construye, lanza y monetiza tu propio SaaS usando IA como asistente estratégico. No es un curso de programación — es una fábrica de fundadores tecnológicos.",
      description2: "Metodología: Construir · Romper · Auditar · Lanzar. 4 meses, Lunes/Miércoles/Viernes, 3h por sesión. Nivel: Base → Intermedio.",
      category: "Desarrollo Web · IA",
      duration: "4 meses",
      level: "Base → Intermedio",
      price: 1800000,
      durationWeeks: 16,
      isActive: true,
      tenantId: tenant.id,
      createdById: userAdmin.id,
    },
    update: { isActive: true },
  });
  console.log(`   ✓ Curso: ${course.title}\n`);

  // ── 5. COHORTE ────────────────────────────────────────────
  console.log("🗓️  Creando cohorte 2025-1...");
  const cohort = await prisma.academyCohort.upsert({
    where: { id: "kaledacademy-cohort-2025-1" },
    create: {
      id: "kaledacademy-cohort-2025-1",
      name: "Cohorte 2025-1",
      startDate: new Date("2025-03-03"),
      endDate: new Date("2025-06-27"),
      maxStudents: 20,
      currentStudents: students.length,
      status: "ACTIVE",
      kind: "ACADEMIC",
      schedule: { days: ["LUNES", "MIERCOLES", "VIERNES"], time: "18:00", duration: 180, timezone: "America/Bogota" },
      courseId: course.id,
      tenantId: tenant.id,
    },
    update: { currentStudents: students.length, kind: "ACADEMIC" },
  });
  console.log(`   ✓ Cohorte: ${cohort.name}\n`);

  // ── 6. MATRICULAR ESTUDIANTES ─────────────────────────────
  console.log("✍️  Matriculando estudiantes...");
  for (const student of students) {
    await prisma.academyEnrollment.upsert({
      where: { userId_courseId: { userId: student.id, courseId: course.id } },
      create: { userId: student.id, courseId: course.id, cohortId: cohort.id, status: "ACTIVE", progress: 0 },
      update: {},
    });
  }
  console.log(`   ✓ ${students.length} estudiantes matriculados\n`);

  // ── 7. BADGES ─────────────────────────────────────────────
  console.log("🏅 Creando badges...");
  const badgeData = [
    { name: "Primera Lección", description: "Completaste tu primera sesión del bootcamp", icon: "🎯", condition: "LESSONS_COMPLETED", threshold: 1 },
    { name: "En Racha", description: "5 lecciones completadas", icon: "🔥", condition: "LESSONS_COMPLETED", threshold: 5 },
    { name: "A Mitad de Camino", description: "24 lecciones completadas", icon: "⚡", condition: "LESSONS_COMPLETED", threshold: 24 },
    { name: "Maratón Completa", description: "Las 48 sesiones completadas", icon: "🏆", condition: "LESSONS_COMPLETED", threshold: 48 },
    { name: "Primer Entregable", description: "Primer entregable aprobado", icon: "📦", condition: "DELIVERABLES_APPROVED", threshold: 1 },
    { name: "Shipper Activo", description: "4 entregables aprobados", icon: "🚀", condition: "DELIVERABLES_APPROVED", threshold: 4 },
    { name: "Maestro del Ship", description: "16 entregables aprobados", icon: "🌟", condition: "DELIVERABLES_APPROVED", threshold: 16 },
    { name: "Quiz Perfecto", description: "Primera respuesta correcta al primer intento", icon: "🧠", condition: "QUIZ_PERFECT_SCORE", threshold: 1 },
    { name: "Primer Deploy", description: "Tu SaaS tiene URL en producción", icon: "☁️", condition: "FIRST_DEPLOY", threshold: null },
    { name: "Fundador Real", description: "Conseguiste 3 usuarios reales en tu SaaS", icon: "👥", condition: "REAL_USERS_3", threshold: null },
    { name: "CRAL Master", description: "Completaste todas las fases CRAL de una semana", icon: "⚙️", condition: "ALL_CRAL_DONE", threshold: null },
    { name: "Demo Day Aprobado", description: "Defendiste y aprobaste el Demo Day final", icon: "🎓", condition: "DEMO_DAY_PASSED", threshold: null },
  ];
  for (const b of badgeData) {
    await prisma.academyBadge.upsert({
      where: { name_tenantId: { name: b.name, tenantId: tenant.id } },
      create: { ...b, tenantId: tenant.id, isActive: true, condition: b.condition as BadgeCondition },
      update: {},
    });
  }
  console.log(`   ✓ ${badgeData.length} badges creados\n`);

  // ── 8. MÓDULOS Y SESIONES ─────────────────────────────────
  console.log("🏗️  Creando los 4 módulos con 48 sesiones...\n");
  await seedModulo1(prisma, course.id, tenant.id);
  await seedModulo2(prisma, course.id, tenant.id);
  await seedModulo3(prisma, course.id, tenant.id);
  await seedModulo4(prisma, course.id, tenant.id);

  // ── 9. MEMORIA INICIAL DE KALED ───────────────────────────
  console.log("\n🤖 Configurando memoria inicial del agente Kaled...");
  const kaledMemories = [
    {
      category: "estrategia_pedagogica",
      content: "El estudiante aprende mejor cuando primero intenta resolver el problema solo. Nunca dar la solución completa sin antes preguntar '¿qué intentaste hasta ahora?'",
      score: 95,
    },
    {
      category: "analogias",
      content: "Las analogías más efectivas para el bootcamp KaledSoft: DNS como directorio telefónico, Git como máquina del tiempo, React como LEGO, Prisma como traductor bilingüe, multi-tenancy como edificio de apartamentos.",
      score: 90,
    },
    {
      category: "manejo_objeciones",
      content: "Cuando el estudiante dice 'no entiendo nada', responder con una analogía de la vida cotidiana colombiana antes de entrar en detalles técnicos. El contexto cultural importa.",
      score: 88,
    },
    {
      category: "patron_conversion",
      content: "Los estudiantes que completan los entregables los viernes tienen 3x más probabilidad de terminar el bootcamp. Priorizar el seguimiento de entregables pendientes.",
      score: 92,
    },
    {
      category: "errores_comunes",
      content: "Los errores más frecuentes en Módulo 1: olvidar el DOCTYPE, no usar HTML semántico, confundir margin con padding. En Módulo 2: mutar estado directamente sin setState. En Módulo 3: N+1 queries con Prisma. En Módulo 4: verificar pagos solo en el frontend.",
      score: 97,
    },
  ];
  for (const mem of kaledMemories) {
    await prisma.agentMemory.create({
      data: { agentType: "KALED", tenantId: tenant.id, ...mem, metadata: { source: "seed_inicial" } },
    });
  }
  console.log(`   ✓ ${kaledMemories.length} memorias de Kaled inicializadas`);

  console.log("\n✅ Seed de KaledAcademy completado exitosamente!");
  console.log(`   Tenant: ${tenant.slug}`);
  console.log(`   Curso: AI SaaS Engineering Bootcamp`);
  console.log(`   Módulos: 4 | Sesiones: 48 | Estudiantes demo: ${students.length}`);
}

